 const restonsZen = "{\"parsed\":{\"_path\":\"/fr/_archived/restons-zen\",\"_dir\":\"_archived\",\"_draft\":false,\"_partial\":true,\"_locale\":\"\",\"title\":\"La théorie du micro et celle du verre d'eau : guide de survie à l'ère des donneurs d'avis\",\"description\":\"Un guide pratique pour rester zen face aux commentaires non sollicités sur Internet. Découvrez comment la théorie du verre d'eau peut vous aider à préserver votre sérénité en ligne.\",\"image\":\"/images/articles/theorieduMicro.webp\",\"createdAt\":\"22-10-2024\",\"id\":5,\"keywords\":\"zen attitude, commentaires non sollicités, réseaux sociaux, santé mentale, gestion des conflits, communication en ligne\",\"summary\":\"Face aux experts auto-proclamés et prophètes numériques qui s'expriment sans retenue sur Internet, découvrez comment la théorie du verre d'eau peut vous aider à rester serein. Un guide pratique pour préserver votre santé mentale en ligne.\",\"og\":{\"title\":\"La théorie du micro et celle du verre d'eau : guide de survie à l'ère des donneurs d'avis\",\"description\":\"Comment rester zen face aux commentaires non sollicités sur Internet ? Découvrez la théorie du verre d'eau, votre allié pour préserver votre sérénité en ligne.\",\"image\":\"/images/articles/theorieduMicro.webp\",\"url\":\"/fr/restons-zen\",\"type\":\"article\",\"site_name\":\"Jean-Luc Houédanou\",\"locale\":\"fr_FR\"},\"twitter\":{\"card\":\"summary_large_image\",\"title\":\"La théorie du micro et celle du verre d'eau : guide de survie à l'ère des donneurs d'avis\",\"description\":\"Face aux experts auto-proclamés sur Internet, découvrez comment la théorie du verre d'eau peut vous aider à rester serein. Un guide pratique pour préserver votre santé mentale en ligne.\",\"image\":\"/images/articles/theorieduMicro.webp\",\"creator\":\"@jeanluchouedanou\"},\"article\":{\"published_time\":\"2024-10-22T00:00:00Z\",\"modified_time\":\"2024-10-22T00:00:00Z\",\"author\":\"Jean-Luc Houédanou\",\"section\":\"Bien-être numérique\",\"tag\":[\"zen attitude\",\"commentaires non sollicités\",\"réseaux sociaux\",\"santé mentale\",\"gestion des conflits\",\"communication en ligne\"]},\"schema\":{\"type\":\"Article\",\"headline\":\"La théorie du micro et celle du verre d'eau : guide de survie à l'ère des donneurs d'avis\",\"description\":\"Un guide pratique pour rester zen face aux commentaires non sollicités sur Internet. Découvrez comment la théorie du verre d'eau peut vous aider à préserver votre sérénité en ligne.\",\"image\":\"/images/articles/theorieduMicro.webp\",\"datePublished\":\"2024-10-22\",\"dateModified\":\"2024-10-22\",\"author\":\"Jean-Luc Houédanou\",\"publisher\":\"Jean-Luc Houédanou\"},\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"la-théorie-du-micro-et-celle-du-verre-deau-guide-de-survie-à-lère-des-donneurs-davis\"},\"children\":[{\"type\":\"text\",\"value\":\"La théorie du micro et celle du verre d'eau : guide de survie à l'ère des donneurs d'avis\"}]},{\"type\":\"element\",\"tag\":\"iframe\",\"props\":{\"width\":\"100%\",\"height\":315,\"src\":\"https://www.youtube.com/embed/ru6yG_WxWVU\",\"title\":\"YouTube video player\",\"frameBorder\":\"0\",\"allow\":\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\",\"allowFullScreen\":true},\"children\":[]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Permettez-moi de vous présenter Sandrine.\\nSandrine, c'est celle qui aime chanter au karaoké.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Elle interprète \\\"Never Leave You\\\" de Lumidee au karaoké avec une passion inversement proportionnelle à son talent.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Imaginez maintenant qu'on lui confie un micro Shure professionnel, le même modèle qu'utilise Beyoncé en studio.\\n\"},{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Cela ne fera pas d'elle une meilleure chanteuse, n'est-ce pas ?\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Internet, c'est exactement cela : on a offert des microphones professionnels à des personnes qui auraient dû rester dans le public. Mais contrairement au karaoké où sévit Sandrine, impossible de s'éclipser discrètement.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"D'où l'importance d'avoir une stratégie.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est là qu'intervient la théorie du verre d'eau.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"le-principe-du-verre-deau\"},\"children\":[{\"type\":\"text\",\"value\":\"Le principe du verre d'eau\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Le concept est d'une simplicité déconcertante : pendant que certains s'époumonent dans leur microphone dernier cri, vous savourez paisiblement votre verre d'eau.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pourquoi de l'eau ? Car elle est :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Transparente (comme votre indifférence à leurs provocations)\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Rafraîchissante (comme votre attitude sereine)\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Essentielle (comme la préservation de votre santé mentale en ligne)\"}]}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"les-virtuoses-du-micro-non-sollicité-et-comment-les-apaiser-avec-votre-verre\"},\"children\":[{\"type\":\"text\",\"value\":\"Les virtuoses du micro non sollicité (et comment les apaiser avec votre verre)\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"lexpert-auto-proclamé\"},\"children\":[{\"type\":\"text\",\"value\":\"L'Expert Auto-proclamé\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Vous postez innocemment : \\\"Ma connexion xxxxx me donne entièrement et pleinement satisfaction. \\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Au micro\"}]},{\"type\":\"text\",\"value\":\" : \\\"MA CONNEXION INTERNET EST SUPÉRIEURE ! J'AI DEUX DÉCENNIES D'EXPÉRIENCE DANS LES RÉSEAUX !\\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Votre verre d'eau\"}]},{\"type\":\"text\",\"value\":\" : Une réponse succincte : \\\"Je vous remercie de votre contribution, bien qu'elle soit non sollicitée\\\".\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Puis dégustez votre eau pendant qu'ils s'évertuent à démontrer leur expertise.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Allez chercher un pichet, car ils peuvent parler pendant longtemps, et chaque mention de leurs \\\"années d'expérience\\\" mérite une gorgée sereine.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ensuite, rajoutez une couche.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"\\\"Madame/Monsieur. Je ne vous ai rien demandé.\\\"\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Puis, vous pouvez ensuite siroter tranquillement votre verre pendant qu'ils s'étouffent avec leur expertise non sollicitée :).\"}]},{\"type\":\"element\",\"tag\":\"h3\",\"props\":{\"id\":\"le-prophète-numérique\"},\"children\":[{\"type\":\"text\",\"value\":\"Le Prophète Numérique\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Au micro\"}]},{\"type\":\"text\",\"value\":\" : \\\"Une reconversion dans le développement ? Le marché est saturé ! Mon neveu crée des sites à prix modique et peine à trouver sa clientèle ! PHP est mort !!! \\\"\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"strong\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Votre verre d'eau\"}]},{\"type\":\"text\",\"value\":\" : Savourez tranquillement votre boisson tout en consultant vos opportunités professionnelles.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Lorsqu'ils ajoutent \\\"L'intelligence artificielle va tout bouleverser\\\", servez-vous un second verre.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ces mêmes oracles prédisaient la fin d'Internet en 2000... avant de créer leur profil Facebook.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"lefficacité-de-cette-approche\"},\"children\":[{\"type\":\"text\",\"value\":\"L'efficacité de cette approche\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pendant qu'ils s'évertuent à faire porter leur voix, vous :\"}]},{\"type\":\"element\",\"tag\":\"ul\",\"props\":{},\"children\":[{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Conservez une sérénité digne d'un maître zen\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Préservez votre énergie pour des activités constructives\"}]},{\"type\":\"element\",\"tag\":\"li\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Évitez ce que l'on nomme à Abidjan \\\"la vie\\\" (entendez : les controverses stériles)\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Plus leur volume sonore augmente, plus votre sérénité s'hydrate. C'est scientifiquement prouvé.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"la-sagesse-du-verre-deau\"},\"children\":[{\"type\":\"text\",\"value\":\"La sagesse du verre d'eau\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"La véritable puissance du verre d'eau réside dans son occupation manuelle. Lorsque la tentation de répondre à un commentaire peu constructif se fait sentir, une gorgée d'eau s'impose. Au minimum, vous serez parfaitement hydraté.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Au mieux, vous aurez évité nombre de débats improductifs.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"en-conclusion\"},\"children\":[{\"type\":\"text\",\"value\":\"En conclusion\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Internet a démocratisé la prise de parole, mais nul n'est tenu d'assister à chaque représentation. Parfois, la réponse la plus appropriée consiste à se retirer élégamment, verre d'eau à la main, laissant les autres se produire en solitaire.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Rappel essentiel : un microphone ne confère pas automatiquement la pertinence du propos.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"L'exemple de Sandrine en est la preuve manifeste.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"P.S. : Mes excuses, Sandrine, pour cette illustration.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ton enthousiasme reste admirable, même si \\\"Never Leave You\\\" ne s'en est jamais vraiment remis et que, depuis sa retraite dorée, \"},{\"type\":\"element\",\"tag\":\"em\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Lumidee se dit que, finalement, elle ne chantait pas si mal que cela.\"}]}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"N.B. : Dans certaines circonstances, le verre d'eau peut être agrémenté de menthe fraîche. Mais ceci relève d'une autre théorie.\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"le-principe-du-verre-deau\",\"depth\":2,\"text\":\"Le principe du verre d'eau\"},{\"id\":\"les-virtuoses-du-micro-non-sollicité-et-comment-les-apaiser-avec-votre-verre\",\"depth\":2,\"text\":\"Les virtuoses du micro non sollicité (et comment les apaiser avec votre verre)\",\"children\":[{\"id\":\"lexpert-auto-proclamé\",\"depth\":3,\"text\":\"L'Expert Auto-proclamé\"},{\"id\":\"le-prophète-numérique\",\"depth\":3,\"text\":\"Le Prophète Numérique\"}]},{\"id\":\"lefficacité-de-cette-approche\",\"depth\":2,\"text\":\"L'efficacité de cette approche\"},{\"id\":\"la-sagesse-du-verre-deau\",\"depth\":2,\"text\":\"La sagesse du verre d'eau\"},{\"id\":\"en-conclusion\",\"depth\":2,\"text\":\"En conclusion\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:_archived:restons-zen.md\",\"_source\":\"content\",\"_file\":\"fr/_archived/restons-zen.md\",\"_stem\":\"fr/_archived/restons-zen\",\"_extension\":\"md\"},\"hash\":\"OUDPEWphxW\"}";

